(function() {
    console.log("Axiom Bot Validator active! টাইপিং শুরু হচ্ছে...");

    // ১. কীবোর্ডের মতো একটা একটা করে অক্ষর টাইপ করার ফাংশন
    async function typeEffect(element, text) {
        if (!element) return;
        element.focus();
        element.value = ""; // আগের লেখা মুছে ফেলা

        for (let char of text) {
            // অক্ষর বসানো
            element.value += char;

            // ইভেন্ট ফায়ার করা যাতে সাইট বুঝতে পারে টাইপ হচ্ছে
            element.dispatchEvent(new Event('input', { bubbles: true }));
            element.dispatchEvent(new Event('change', { bubbles: true }));

            // প্রতিটি অক্ষরের মাঝে ১০০ মিলিসেকেন্ড বিরতি (টাইপিং স্পিড)
            await new Promise(resolve => setTimeout(resolve, 100));
        }
    }

    // ২. মেইন অটোমেশন লজিক
    async function startAutomation() {
        // --- স্ক্রিন ১: নাম পূরণ ---
        const fname = document.getElementById('fname');
        const lname = document.getElementById('lname');
        if (fname && lname) {
            await typeEffect(fname, "Axiom");
            await typeEffect(lname, "Browser");
            await new Promise(r => setTimeout(r, 500));
            document.querySelector('#screen1 .btn-next').click();
        }

        // --- স্ক্রিন ২: বয়স (Day, Month, Year) ---
        await new Promise(r => setTimeout(r, 1000)); // স্ক্রিন পরিবর্তনের জন্য অপেক্ষা
        const day = document.getElementById('day');
        const month = document.getElementById('month');
        const year = document.getElementById('year');
        if (day && month && year) {
            await typeEffect(day, "16");
            await typeEffect(month, "02");
            await typeEffect(year, "2026");
            await new Promise(r => setTimeout(r, 500));
            document.querySelector('#screen2 .btn-next').click();
        }

        // --- স্ক্রিন ৩: ইমেইল ---
        await new Promise(r => setTimeout(r, 1000));
        const email = document.getElementById('email');
        if (email) {
            await typeEffect(email, "bot@axiom.com");
            await new Promise(r => setTimeout(r, 500));
            document.querySelector('#screen3 .btn-next').click();
        }

        // --- স্ক্রিন ৪: পাসওয়ার্ড ---
        await new Promise(r => setTimeout(r, 1000));
        const pass = document.getElementById('pass');
        if (pass) {
            await typeEffect(pass, "SecurePass123");
            await new Promise(r => setTimeout(r, 500));
            document.querySelector('#screen4 .btn-next').click();
        }

        console.log("মিশন সফল! ফর্ম সাবমিট হয়েছে। 🎉");
    }

    // বট চালু করা
    startAutomation();

})();
